-- updated_at trigger function used by multiple tables
CREATE OR REPLACE FUNCTION tg__set_updated_at() RETURNS trigger AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TYPE habit_proof_mode AS ENUM ('self_attest', 'photo_hash_local', 'external_verifier');
CREATE TABLE IF NOT EXISTS habits (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  cadence JSONB NOT NULL DEFAULT '{}'::jsonb,
  floor_seconds INT NOT NULL,
  target_seconds INT NOT NULL,
  stretch_seconds INT NOT NULL,
  proof_mode habit_proof_mode NOT NULL DEFAULT 'self_attest',
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_habits_user ON habits(user_id);
CREATE TRIGGER habits_set_updated_at
  BEFORE UPDATE ON habits
  FOR EACH ROW EXECUTE FUNCTION tg__set_updated_at();
-- Enforce max 3 active habits per user via trigger
CREATE OR REPLACE FUNCTION enforce_max_active_habits() RETURNS trigger AS $$
BEGIN
  IF NEW.is_active THEN
    IF (SELECT COUNT(*) FROM habits WHERE user_id = NEW.user_id AND is_active) >= 3 THEN
      RAISE EXCEPTION 'max_active_habits=3 exceeded for user %', NEW.user_id;
    END IF;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_enforce_max_active_habits ON habits;
CREATE TRIGGER trg_enforce_max_active_habits
  BEFORE INSERT OR UPDATE OF is_active ON habits
  FOR EACH ROW EXECUTE FUNCTION enforce_max_active_habits();

CREATE TYPE session_status AS ENUM ('started','floor_reached','completed','cancelled','abandoned');
CREATE TABLE IF NOT EXISTS sessions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  habit_id UUID NOT NULL REFERENCES habits(id) ON DELETE CASCADE,
  device_id TEXT,
  status session_status NOT NULL DEFAULT 'started',
  started_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  floor_reached_at TIMESTAMPTZ,
  completed_at TIMESTAMPTZ,
  last_heartbeat_at TIMESTAMPTZ,
  client_clock_skew_ms INT DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_sessions_user_status ON sessions(user_id, status);
CREATE INDEX IF NOT EXISTS idx_sessions_habit ON sessions(habit_id);

CREATE TYPE session_event_type AS ENUM ('started','floor_reached','heartbeat','completed','cancelled');
CREATE TABLE IF NOT EXISTS session_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  session_id UUID NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
  event_type session_event_type NOT NULL,
  event_ts TIMESTAMPTZ NOT NULL DEFAULT now(),
  client_ts TIMESTAMPTZ,
  client_event_id TEXT,
  payload JSONB NOT NULL DEFAULT '{}'::jsonb
);
CREATE INDEX IF NOT EXISTS idx_session_events_session ON session_events(session_id);
CREATE INDEX IF NOT EXISTS idx_session_events_type ON session_events(event_type);
-- Idempotency for client-submitted events
CREATE UNIQUE INDEX IF NOT EXISTS uq_session_client_event
  ON session_events(session_id, client_event_id)
  WHERE client_event_id IS NOT NULL;

CREATE TABLE IF NOT EXISTS token_buckets (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL UNIQUE REFERENCES users(id) ON DELETE CASCADE,
  balance INT NOT NULL DEFAULT 0,
  capacity INT NOT NULL DEFAULT 100,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE TRIGGER token_buckets_set_updated_at
  BEFORE UPDATE ON token_buckets
  FOR EACH ROW EXECUTE FUNCTION tg__set_updated_at();
CREATE TABLE IF NOT EXISTS token_transactions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  amount INT NOT NULL,
  reason TEXT NOT NULL,
  session_id UUID REFERENCES sessions(id) ON DELETE SET NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_token_tx_user ON token_transactions(user_id);

CREATE TYPE floor_change_reason AS ENUM ('ema_raise','ema_lower','manual_override');
CREATE TABLE IF NOT EXISTS floor_history (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  habit_id UUID NOT NULL REFERENCES habits(id) ON DELETE CASCADE,
  effective_date DATE NOT NULL,
  prev_floor_seconds INT NOT NULL,
  new_floor_seconds INT NOT NULL,
  ema_snapshot JSONB NOT NULL,
  reason floor_change_reason NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_floor_history_habit ON floor_history(habit_id, effective_date);

CREATE TABLE IF NOT EXISTS refresh_tokens (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  token_hash TEXT NOT NULL,
  issued_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  expires_at TIMESTAMPTZ NOT NULL,
  revoked BOOLEAN NOT NULL DEFAULT FALSE,
  metadata JSONB NOT NULL DEFAULT '{}'::jsonb
);
CREATE INDEX IF NOT EXISTS idx_refresh_user ON refresh_tokens(user_id);
